import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getHistory } from '../services/resume';
import Card from '../components/UI/Card';
import Button from '../components/UI/Button';
import { 
  DocumentTextIcon, 
  ChartBarIcon, 
  AcademicCapIcon,
  ArrowPathIcon,
  SparklesIcon,
  ClockIcon,
  CheckCircleIcon,
  ArrowTrendingUpIcon  // Changed from TrendingUpIcon to ArrowTrendingUpIcon
} from '@heroicons/react/24/outline';

const Dashboard = () => {
  const { user } = useAuth();
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState({
    total: 0,
    avgAts: 0,
    highestMatch: 0,
    improvementRate: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadHistory();
  }, []);

  const loadHistory = async () => {
    try {
      const data = await getHistory();
      setHistory(data);
      
      if (data.length > 0) {
        const avg = data.reduce((acc, curr) => acc + curr.atsScore, 0) / data.length;
        const highest = Math.max(...data.map(item => item.matchPercentage));
        setStats({
          total: data.length,
          avgAts: Math.round(avg * 10) / 10,
          highestMatch: highest,
          improvementRate: data.length > 1 ? 
            Math.round((data[0].atsScore - data[data.length-1].atsScore) / data[data.length-1].atsScore * 100) : 0
        });
      }
    } catch (error) {
      console.error('Failed to load history:', error);
    } finally {
      setLoading(false);
    }
  };

  const statsCards = [
    {
      title: 'Total Analyses',
      value: stats.total,
      icon: DocumentTextIcon,
      color: 'from-blue-500 to-cyan-500',
      bgColor: 'bg-blue-50',
      textColor: 'text-blue-600'
    },
    {
      title: 'Avg. ATS Score',
      value: `${stats.avgAts}%`,
      icon: ChartBarIcon,
      color: 'from-green-500 to-emerald-500',
      bgColor: 'bg-green-50',
      textColor: 'text-green-600'
    },
    {
      title: 'Best Match',
      value: `${stats.highestMatch}%`,
      icon: ArrowTrendingUpIcon,  // Changed from TrendingUpIcon
      color: 'from-purple-500 to-pink-500',
      bgColor: 'bg-purple-50',
      textColor: 'text-purple-600'
    },
  ];

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <ArrowPathIcon className="h-12 w-12 text-indigo-600 animate-spin mx-auto mb-4" />
          <p className="text-gray-600">Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Welcome Section */}
        <div className="mb-8">
          <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-8 text-white">
            <div className="flex items-center justify-between">
              <div>
                <h1 className="text-3xl font-bold mb-2">
                  Welcome back, {user?.name?.split(' ')[0]}! 👋
                </h1>
                <p className="text-indigo-100 text-lg">
                  Ready to optimize your resume and land your dream job?
                </p>
              </div>
              <SparklesIcon className="h-16 w-16 text-white opacity-20" />
            </div>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          {statsCards.map((stat, index) => (
            <Card key={index} hover className="relative overflow-hidden">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-500 mb-1">{stat.title}</p>
                  <p className="text-3xl font-bold text-gray-900">{stat.value}</p>
                </div>
                <div className={`${stat.bgColor} p-3 rounded-xl`}>
                  <stat.icon className={`h-6 w-6 ${stat.textColor}`} />
                </div>
              </div>
              <div className={`absolute bottom-0 left-0 h-1 bg-gradient-to-r ${stat.color}`} style={{ width: '30%' }} />
            </Card>
          ))}
        </div>

        {/* Quick Action */}
        <div className="mb-8">
          <Card className="text-center border-2 border-dashed border-indigo-200 hover:border-indigo-400 transition-all">
            <div className="py-8">
              <div className="inline-flex p-3 bg-indigo-100 rounded-full mb-4">
                <SparklesIcon className="h-8 w-8 text-indigo-600" />
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">
                Ready to analyze your resume?
              </h3>
              <p className="text-gray-500 mb-6">
                Get instant AI-powered feedback on your resume against any job description
              </p>
              <Link to="/analyze">
                <Button variant="primary" size="lg">
                  Start New Analysis
                </Button>
              </Link>
            </div>
          </Card>
        </div>

        {/* Recent History */}
        <Card>
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center space-x-2">
              <ClockIcon className="h-5 w-5 text-gray-500" />
              <h2 className="text-xl font-semibold text-gray-900">Recent Analyses</h2>
            </div>
            {history.length > 0 && (
              <Button variant="secondary" size="sm" onClick={() => loadHistory()}>
                <ArrowPathIcon className="h-4 w-4 mr-1" />
                Refresh
              </Button>
            )}
          </div>

          {history.length === 0 ? (
            <div className="text-center py-12">
              <DocumentTextIcon className="h-16 w-16 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-500 text-lg mb-2">No analysis history yet</p>
              <p className="text-gray-400 mb-6">Start your first analysis to see results here</p>
              <Link to="/analyze">
                <Button variant="primary">
                  Start Your First Analysis
                </Button>
              </Link>
            </div>
          ) : (
            <div className="space-y-4">
              {history.map((item) => (
                <Link
                  key={item._id}
                  to={`/result/${item._id}`}
                  className="block group"
                >
                  <div className="p-4 border border-gray-200 rounded-xl hover:border-indigo-300 hover:shadow-md transition-all">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-4">
                        <div className="bg-gray-100 p-3 rounded-xl group-hover:bg-indigo-50 transition-colors">
                          <DocumentTextIcon className="h-5 w-5 text-gray-600 group-hover:text-indigo-600" />
                        </div>
                        <div>
                          <p className="font-medium text-gray-900">
                            {item.fileName || 'Resume Analysis'}
                          </p>
                          <div className="flex items-center text-sm text-gray-500 mt-1">
                            <ClockIcon className="h-4 w-4 mr-1" />
                            {new Date(item.createdAt).toLocaleDateString('en-US', {
                              month: 'short',
                              day: 'numeric',
                              year: 'numeric',
                              hour: '2-digit',
                              minute: '2-digit'
                            })}
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center space-x-6">
                        <div className="text-center">
                          <p className="text-xs text-gray-500 mb-1">ATS Score</p>
                          <div className="flex items-center space-x-2">
                            <div className="w-16 h-2 bg-gray-200 rounded-full overflow-hidden">
                              <div 
                                className={`h-full rounded-full ${
                                  item.atsScore >= 70 ? 'bg-green-500' : 
                                  item.atsScore >= 50 ? 'bg-yellow-500' : 'bg-red-500'
                                }`}
                                style={{ width: `${item.atsScore}%` }}
                              />
                            </div>
                            <span className={`text-sm font-semibold ${
                              item.atsScore >= 70 ? 'text-green-600' : 
                              item.atsScore >= 50 ? 'text-yellow-600' : 'text-red-600'
                            }`}>
                              {item.atsScore}%
                            </span>
                          </div>
                        </div>
                        <div className="text-center">
                          <p className="text-xs text-gray-500 mb-1">Match</p>
                          <div className="flex items-center space-x-2">
                            <div className="w-16 h-2 bg-gray-200 rounded-full overflow-hidden">
                              <div 
                                className="h-full rounded-full bg-indigo-500"
                                style={{ width: `${item.matchPercentage}%` }}
                              />
                            </div>
                            <span className="text-sm font-semibold text-indigo-600">
                              {item.matchPercentage}%
                            </span>
                          </div>
                        </div>
                        <CheckCircleIcon className="h-5 w-5 text-gray-400 group-hover:text-indigo-600 transition-colors" />
                      </div>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          )}
        </Card>
      </div>
    </div>
  );
};

export default Dashboard;
